SELECT t.task_id, t.task_name, t.description, t.complexity, t.default_model, t.performance_metrics, c.creator_name, c.affiliation, c.contact_email
FROM tasks t
JOIN creators c ON t.default_model = c.creator_name;

SELECT t.task_name, t.description, c.creator_name
FROM tasks t
JOIN creators c ON t.default_model = c.creator_name;
